                     <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useState, useMemo, useImperativeHandle, forwardRef, useCallback, useRef } from 'react';
import { Icon } from '../UI';
import { Standard, MatrixRow, UploadedFile, Clause } from '../../types';
import { copyToClipboard, serializeMatrixData } from '../../utils';
import { useStandardUtils } from '../../hooks/useStandardUtils';

export interface EvidenceMatrixHandle {
    insertEvidence: (clauseId: string, rowId: string, text: string) => void;
    handleExternalDictation: (text: string) => void;
    getActiveRow: () => { clauseId: string, rowId: string } | null;
}

interface EvidenceMatrixProps {
    standard: Standard;
    selectedClauses: string[];
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    onPasteFiles?: (files: File[], target: { clauseId: string, rowId: string }) => void;
    uploadedFiles?: UploadedFile[];
    onRemoveFile?: (fileId: string) => void;
    onLookup?: (clause: Clause) => void;
}

// --- MAIN COMPONENT ---
export const EvidenceMatrix = forwardRef<EvidenceMatrixHandle, EvidenceMatrixProps>(({
    standard, selectedClauses, matrixData, setMatrixData, onPasteFiles, uploadedFiles = [], onRemoveFile, onLookup
}, ref) => {

    // Tracking active row
    const [activeRow, setActiveRow] = useState<{ clauseId: string, rowId: string } | null>(null);
    const textAreaRef = useRef<HTMLTextAreaElement>(null);

    // Optimized utility hook
    const { getClauseById } = useStandardUtils(standard);

    // Initialization Logic
    useEffect(() => {
        setMatrixData(currentMatrix => {
            const newMatrix = { ...currentMatrix };
            let updated = false;
            let firstRowFound: { clauseId: string, rowId: string } | null = null;

            selectedClauses.forEach(clauseId => {
                // Initialize missing rows
                if (!newMatrix[clauseId] || newMatrix[clauseId].length === 0) {
                    const clause = getClauseById(clauseId);
                    if (clause) {
                        const desc = clause.description || "Requirement";
                        const reqs = desc.length > 300 
                            ? desc.split(/(?:\. |\n)/).filter(s => s.trim().length > 5) 
                            : [desc];

                        newMatrix[clauseId] = reqs.map((req, idx) => ({
                            id: `${clauseId}_req_${idx}`,
                            requirement: req.trim(),
                            evidenceInput: "",
                            status: 'pending'
                        }));
                        updated = true;
                    }
                }
                // Determine default active row if none
                if (!firstRowFound && newMatrix[clauseId] && newMatrix[clauseId].length > 0) {
                    firstRowFound = { clauseId, rowId: newMatrix[clauseId][0].id };
                }
            });

            if (!activeRow && firstRowFound) {
                setActiveRow(firstRowFound);
            }

            return updated ? newMatrix : currentMatrix;
        });
    }, [selectedClauses, getClauseById, setMatrixData]); // Depend only on stable props

    // --- HANDLERS ---
    const updateRowData = useCallback((clauseId: string, rowId: string, textToAppend: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => {
                if (row.id === rowId) {
                    const currentText = row.evidenceInput || "";
                    const separator = currentText && textToAppend ? "\n" : "";
                    const newText = currentText + separator + textToAppend;
                    return { ...row, evidenceInput: newText, status: newText.trim() ? 'supplied' : 'pending' };
                }
                return row;
            })
        }));
    }, [setMatrixData]);

    // OPTIMIZED: Direct state update for typing to avoid lag
    const handleInputChange = useCallback((clauseId: string, rowId: string, value: string) => {
        setMatrixData(prev => {
            const currentRows = prev[clauseId];
            if (!currentRows) return prev;

            // Optimization: Only create new object if value actually changed
            const rowIndex = currentRows.findIndex(r => r.id === rowId);
            if (rowIndex === -1 || currentRows[rowIndex].evidenceInput === value) return prev;

            const newRows = [...currentRows];
            newRows[rowIndex] = { 
                ...newRows[rowIndex], 
                evidenceInput: value, 
                status: value.trim() ? 'supplied' : 'pending' 
            };

            return { ...prev, [clauseId]: newRows };
        });
    }, [setMatrixData]);

    const handlePaste = useCallback((e: React.ClipboardEvent, clauseId: string, rowId: string) => {
        const items = e.clipboardData.items;
        const files: File[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const f = items[i].getAsFile();
                if (f) files.push(f);
            }
        }
        if (files.length > 0) {
            e.preventDefault();
            if (onPasteFiles) {
                onPasteFiles(files, { clauseId, rowId });
            }
        }
    }, [onPasteFiles]);

    // IMPERATIVE HANDLE
    useImperativeHandle(ref, () => ({
        insertEvidence: (clauseId, rowId, text) => updateRowData(clauseId, rowId, text),
        handleExternalDictation: (text) => { if (activeRow) updateRowData(activeRow.clauseId, activeRow.rowId, text); },
        getActiveRow: () => activeRow
    }));

    // --- DERIVED ACTIVE DATA ---
    const activeData = useMemo(() => {
        if (!activeRow) return null;
        const clause = getClauseById(activeRow.clauseId);
        const rows = matrixData[activeRow.clauseId];
        const row = rows?.find(r => r.id === activeRow.rowId);
        if (!clause || !row) return null;
        return { clause, row };
    }, [activeRow, matrixData, getClauseById]);

    const renderFilePreview = (fileEntry: UploadedFile) => {
        const isImage = fileEntry.file.type.startsWith('image/');
        const isPdf = fileEntry.file.type.includes('pdf');

        return (
            <div key={fileEntry.id} className="relative group w-20 h-20 bg-gray-50 dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 flex flex-col items-center justify-center overflow-hidden transition-all hover:shadow-md hover:-translate-y-1">
                {isImage ? (
                    <img src={URL.createObjectURL(fileEntry.file)} alt="preview" className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
                ) : (
                    <div className="flex flex-col items-center p-2 text-center">
                        <Icon name={isPdf ? "BookOpen" : "FileText"} size={24} className="text-slate-400 mb-1"/>
                        <span className="text-[9px] text-slate-500 line-clamp-2 leading-tight break-all">{fileEntry.file.name}</span>
                    </div>
                )}

                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-start justify-end p-1">
                    {fileEntry.status === 'processing' && (
                        <div className="absolute inset-0 bg-white/80 dark:bg-black/50 flex items-center justify-center">
                            <Icon name="Loader" size={16} className="animate-spin text-indigo-600"/>
                        </div>
                    )}
                    {fileEntry.status === 'success' && <div className="bg-emerald-500 rounded-full p-0.5 shadow-sm"><Icon name="CheckThick" size={10} className="text-white"/></div>}

                    <button 
                        onClick={(e) => { e.stopPropagation(); onRemoveFile && onRemoveFile(fileEntry.id); }}
                        className="bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-all hover:scale-110 shadow-sm"
                        title="Remove File"
                    >
                        <Icon name="X" size={10}/>
                    </button>
                </div>
            </div>
        );
    };

    if (selectedClauses.length === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/30 dark:bg-slate-900/30 rounded-3xl border-2 border-dashed border-gray-200 dark:border-slate-800 m-4">
                <div className="p-6 bg-white dark:bg-slate-900 rounded-full shadow-depth mb-4">
                    <Icon name="LayoutList" size={48} className="text-indigo-200 dark:text-slate-700"/>
                </div>
                <p className="text-sm font-bold text-slate-500">Select clauses to start mapping evidence.</p>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col relative animate-fade-in-up">
            {/* CONTENT AREA */}
            <div className="flex-1 min-h-0 bg-white dark:bg-slate-900 rounded-2xl border border-white/60 dark:border-slate-800 shadow-depth overflow-hidden flex">

                {/* LIST COLUMN */}
                <div className="w-1/3 min-w-[260px] max-w-[350px] border-r border-gray-100 dark:border-slate-800 flex flex-col bg-slate-50/50 dark:bg-slate-950/30 backdrop-blur-sm">
                    <div className="p-3 border-b border-gray-100 dark:border-slate-800 flex justify-between items-center bg-white/50 dark:bg-slate-900/50">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Requirement Checklist</span>
                        <button 
                            onClick={() => { const t = serializeMatrixData(matrixData, selectedClauses); if(t) copyToClipboard(t); }}
                            className="text-[10px] text-indigo-500 hover:text-indigo-600 font-bold flex items-center gap-1 transition-colors"
                        >
                            <Icon name="Copy" size={10}/> Copy All
                        </button>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">
                        {selectedClauses.map(clauseId => {
                            const clause = getClauseById(clauseId);
                            const rows = matrixData[clauseId] || [];
                            if(!clause) return null;

                            return (
                                <div key={clauseId} className="space-y-1">
                                    <div className="flex items-center justify-between gap-2 px-2 py-1.5 group/header rounded-lg hover:bg-white dark:hover:bg-slate-800 transition-colors">
                                        <div className="flex items-center gap-2 overflow-hidden">
                                            <span className="text-[10px] font-black text-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 px-1.5 py-0.5 rounded flex-shrink-0 border border-indigo-100 dark:border-indigo-800/50">{clause.code}</span>
                                            <span className="text-xs font-bold text-slate-700 dark:text-slate-300 truncate" title={clause.title}>{clause.title}</span>
                                        </div>
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onLookup && onLookup(clause); }}
                                            className="p-1 text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded opacity-0 group-hover/header:opacity-100 transition-all scale-90 hover:scale-100"
                                            title="Read Clause Content"
                                        >
                                            <Icon name="BookOpen" size={12}/>
                                        </button>
                                    </div>
                                    <div className="pl-2 space-y-1">
                                        {rows.map((row) => {
                                            const isActive = activeRow?.rowId === row.id;
                                            const isDone = row.status === 'supplied';
                                            return (
                                                <div 
                                                    key={row.id}
                                                    onClick={() => setActiveRow({ clauseId, rowId: row.id })}
                                                    className={`group relative p-3 rounded-xl cursor-pointer transition-all border ${isActive ? 'bg-white dark:bg-slate-800 border-indigo-200 dark:border-indigo-600 shadow-sm ring-1 ring-indigo-500/10' : 'bg-transparent border-transparent hover:bg-white dark:hover:bg-slate-800/50 hover:border-slate-200 dark:hover:border-slate-700'}`}
                                                >
                                                    <div className="flex items-start gap-2.5">
                                                        <div className={`mt-1 w-2.5 h-2.5 rounded-full shrink-0 transition-all shadow-sm ${isDone ? 'bg-emerald-500 scale-110' : isActive ? 'bg-indigo-500 scale-110' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                                        <p className={`text-[11px] leading-relaxed line-clamp-3 ${isActive ? 'text-slate-800 dark:text-slate-100 font-medium' : 'text-slate-500 dark:text-slate-400'}`}>
                                                            {row.requirement}
                                                        </p>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* EDITOR COLUMN */}
                <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 min-w-0 relative">
                    {activeData ? (
                        <div className="flex flex-col h-full animate-in fade-in zoom-in-95 duration-200">
                            {/* Requirement Context Header */}
                            <div className="p-5 border-b border-gray-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
                                <div className="flex items-center justify-between gap-3 mb-3">
                                    <div className="flex items-center gap-3">
                                        <span className="text-xs font-black text-white bg-gradient-to-r from-indigo-500 to-purple-500 px-2 py-0.5 rounded shadow-sm">{activeData.clause.code}</span>
                                        <span className="text-sm font-bold text-slate-800 dark:text-white tracking-tight">{activeData.clause.title}</span>
                                    </div>
                                    <button 
                                        onClick={() => onLookup && onLookup(activeData.clause)}
                                        className="flex items-center gap-1.5 px-3 py-1.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-lg text-xs font-bold text-slate-600 dark:text-slate-300 hover:text-indigo-600 dark:hover:text-indigo-400 hover:border-indigo-300 transition-all shadow-sm active:scale-95"
                                    >
                                        <Icon name="BookOpen" size={14}/>
                                        Ref
                                    </button>
                                </div>
                                <div className="bg-white dark:bg-slate-800 p-3 rounded-lg border-l-4 border-indigo-400 dark:border-indigo-600 shadow-sm">
                                    <p className="text-xs text-slate-600 dark:text-slate-300 leading-relaxed font-medium">
                                        {activeData.row.requirement}
                                    </p>
                                </div>
                            </div>

                            {/* FILES GRID */}
                            {uploadedFiles.length > 0 && (
                                <div className="px-6 pt-4 pb-2 bg-slate-50/30 dark:bg-black/10">
                                    <div className="flex flex-wrap gap-3">
                                        {uploadedFiles.map(renderFilePreview)}
                                    </div>
                                </div>
                            )}

                            {/* Large Editor Area */}
                            <div className="flex-1 relative group">
                                <textarea
                                    ref={textAreaRef}
                                    className="w-full h-full p-6 text-base text-slate-800 dark:text-slate-200 bg-transparent outline-none resize-none leading-7 placeholder-slate-300 dark:placeholder-slate-600 font-medium"
                                    placeholder="Type verified evidence here... (Drag & Drop files supported)"
                                    value={activeData.row.evidenceInput}
                                    onChange={(e) => handleInputChange(activeData.clause.id, activeData.row.id, e.target.value)}
                                    onPaste={(e) => handlePaste(e, activeData.clause.id, activeData.row.id)}
                                    autoFocus
                                />

                                {/* Floating Actions */}
                                <div className="absolute bottom-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                                    {activeData.row.status === 'supplied' && (
                                        <span className="px-3 py-1.5 bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 rounded-full text-xs font-bold flex items-center gap-1 shadow-sm border border-emerald-200 dark:border-emerald-800">
                                            <Icon name="CheckThick" size={12}/> Saved
                                        </span>
                                    )}
                                    <button 
                                        onClick={() => handleInputChange(activeData.clause.id, activeData.row.id, "")}
                                        className="p-2 bg-white dark:bg-slate-800 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-lg transition-colors shadow-sm border border-gray-200 dark:border-slate-700"
                                        title="Clear Text"
                                    >
                                        <Icon name="Trash2" size={16}/>
                                    </button>
                                </div>
                            </div>

                            {/* Footer Info */}
                            <div className="px-6 py-2 border-t border-gray-100 dark:border-slate-800 text-[10px] text-slate-400 flex justify-between bg-gray-50/80 dark:bg-slate-950/80 backdrop-blur-sm">
                                <span className="font-mono">Ln {activeData.row.evidenceInput.split('\n').length}, Col {activeData.row.evidenceInput.length}</span>
                                <span>{uploadedFiles.length} Attachment(s)</span>
                            </div>
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-slate-300 dark:text-slate-600">
                            <Icon name="ArrowLeft" size={32} className="mb-2 opacity-50"/>
                            <p className="text-sm">Select a requirement from the checklist</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
});

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { Icon } from '../UI';
import { AnalysisResult, FindingStatus, FindingsViewMode } from '../../types';
import { TABS_CONFIG } from '../../constants';
import { performShadowReview } from '../../services/geminiService';
import { useKeyPool } from '../../contexts/KeyPoolContext';
import { useUI } from '../../contexts/UIContext';

interface FindingsViewProps {
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    isAnalyzeLoading: boolean;
    loadingMessage: string;
    currentAnalyzingClause: string;
    viewMode: FindingsViewMode;
    setViewMode: (mode: FindingsViewMode) => void;
    focusedFindingIndex: number;
    setFocusedFindingIndex: (index: number) => void;
    onExport: (type: 'notes', lang: 'en' | 'vi') => void;
    notesLanguage: 'en' | 'vi';
    setNotesLanguage: (lang: 'en' | 'vi') => void;
}

export const FindingsView: React.FC<FindingsViewProps> = ({
    analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
    isAnalyzeLoading, loadingMessage, currentAnalyzingClause,
    viewMode, setViewMode, focusedFindingIndex, setFocusedFindingIndex,
    onExport, notesLanguage, setNotesLanguage
}) => {
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);
    const { getActiveKey } = useKeyPool();
    const { showToast } = useUI();

    // Local state for Shadow Review
    const [reviewLoading, setReviewLoading] = useState<string | null>(null); // Clause ID
    const [reviews, setReviews] = useState<Record<string, string>>({});

    // Grouping State
    const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

    // Matrix Visibility State
    const [isMatrixCollapsed, setIsMatrixCollapsed] = useState(false);

    const themeConfig = TABS_CONFIG.find(t => t.id === 'findings')!;

    useEffect(() => {
        if (viewMode === 'list' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult?.length, viewMode]);

    // Computed: Are all visible items selected?
    const isAllSelected = useMemo(() => {
        if (!analysisResult || analysisResult.length === 0) return false;
        return analysisResult.every(res => selectedFindings[res.clauseId]);
    }, [analysisResult, selectedFindings]);

    // Computed: Group Findings by Process
    const groupedFindings = useMemo((): Record<string, { finding: AnalysisResult, originalIndex: number }[]> => {
        if (!analysisResult) return {};
        const groups: Record<string, { finding: AnalysisResult, originalIndex: number }[]> = {};

        analysisResult.forEach((finding, index) => {
            const processName = finding.processName || "General Audit";
            if (!groups[processName]) {
                groups[processName] = [];
            }
            groups[processName].push({ finding, originalIndex: index });
        });

        // Sort keys to ensure consistent order
        return Object.keys(groups).sort().reduce((acc, key) => {
            acc[key] = groups[key];
            return acc;
        }, {} as typeof groups);
    }, [analysisResult]);

    const toggleGroup = (groupName: string) => {
        setCollapsedGroups(prev => {
            const next = new Set(prev);
            if (next.has(groupName)) next.delete(groupName);
            else next.add(groupName);
            return next;
        });
    };

    const handleToggleSelectAll = () => {
        if (!analysisResult) return;
        const newSelection: Record<string, boolean> = {};
        const targetState = !isAllSelected;

        analysisResult.forEach(res => {
            newSelection[res.clauseId] = targetState;
        });

        setSelectedFindings(prev => ({ ...prev, ...newSelection }));
        showToast(targetState ? "All Findings Selected" : "All Findings Deselected");
    };

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
        // Auto-scroll only on status change, not text editing
        if (field === 'status' && analysisResult) {
            const nextIndex = index + 1;
            if (nextIndex < analysisResult.length && findingRefs.current[nextIndex]) {
                setTimeout(() => findingRefs.current[nextIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' }), 100);
            }
        }
    };

    const handleShadowReview = async (e: React.MouseEvent, finding: AnalysisResult) => {
        e.stopPropagation();
        const keyProfile = getActiveKey();
        if (!keyProfile) return showToast("API Key Required for Review");

        setReviewLoading(finding.clauseId);
        try {
            const critique = await performShadowReview(finding, keyProfile.key, keyProfile.activeModel);
            setReviews(prev => ({ ...prev, [finding.clauseId]: critique }));
        } catch (err) {
            showToast("Review Failed");
        } finally {
            setReviewLoading(null);
        }
    };

    const getFindingColorStyles = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return { bg: 'bg-emerald-500', text: 'text-emerald-700 dark:text-emerald-300', pill: 'bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300', border: 'border-emerald-500' };
            case 'NC_MAJOR': return { bg: 'bg-red-600', text: 'text-red-700 dark:text-red-300', pill: 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300', border: 'border-red-600' };
            case 'NC_MINOR': return { bg: 'bg-orange-500', text: 'text-orange-700 dark:text-orange-300', pill: 'bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300', border: 'border-orange-500' };
            case 'OFI': return { bg: 'bg-blue-500', text: 'text-blue-700 dark:text-blue-300', pill: 'bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300', border: 'border-blue-500' };
            default: return { bg: 'bg-slate-500', text: 'text-slate-600', pill: 'bg-slate-100 text-slate-500', border: 'border-slate-300' };
        }
    };

    const renderFindingCard = (res: AnalysisResult, idx: number, isCondensed = false) => {
        const styles = getFindingColorStyles(res.status as FindingStatus);
        const reviewText = reviews[res.clauseId];
        const isReviewing = reviewLoading === res.clauseId;

        return (
            <div
                key={idx}
                ref={!isCondensed ? el => { findingRefs.current[idx] = el; } : null}
                className={`group relative bg-white dark:bg-slate-900 rounded-2xl p-4 md:p-5 border-l-[6px] transition-all duration-300 hover:shadow-depth-lg dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05)] ${styles.border} ${selectedFindings[res.clauseId] ? 'ring-2 ring-indigo-500/20 translate-x-2' : 'hover:translate-x-1 opacity-60 hover:opacity-100'} animate-in slide-in-from-bottom-2 fade-in fill-mode-backwards`}
                style={{ animationDelay: `${idx * 50}ms` }}
                onClick={() => setSelectedFindings(prev => ({ ...prev, [res.clauseId]: !prev[res.clauseId] }))}
            >
                {/* Header Controls */}
                <div className="absolute top-4 right-4 z-10 flex gap-2">
                    <button 
                        onClick={(e) => handleShadowReview(e, res)}
                        disabled={isReviewing}
                        className={`p-1.5 rounded-full transition-all border ${reviewText ? 'bg-purple-100 text-purple-600 border-purple-200' : 'bg-gray-100 text-slate-400 hover:text-purple-600 hover:bg-purple-50 border-transparent'}`}
                        title="AI Shadow Review (Critique Finding)"
                    >
                        {isReviewing ? <Icon name="Loader" className="animate-spin" size={14}/> : <Icon name="ShieldEye" size={14}/>}
                    </button>
                    {selectedFindings[res.clauseId] ? (
                        <div className="bg-emerald-100 dark:bg-emerald-900/30 rounded-full p-1 text-emerald-600 dark:text-emerald-400">
                            <Icon name="CheckThick" size={18} />
                        </div>
                    ) : (
                        <div className="w-6 h-6 rounded-full border-2 border-gray-200 dark:border-slate-700 group-hover:border-indigo-400 transition-colors"></div>
                    )}
                </div>

                <div className="pr-12">
                    <div className="flex items-center gap-3 mb-4 flex-wrap">
                        <span className="text-xs font-black text-slate-500 dark:text-slate-400 bg-gray-100 dark:bg-slate-800 px-2 py-1 rounded-lg border border-gray-200 dark:border-slate-700">{res.clauseId}</span>
                        {res.processName && (
                            <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800 flex items-center gap-1">
                                <Icon name="Session11_GridAdd" size={10} /> {res.processName}
                            </span>
                        )}
                        <div className="relative group/badge" onClick={e => e.stopPropagation()}>
                            <select
                                value={res.status}
                                onChange={(e) => handleUpdateFinding(idx, 'status', e.target.value)}
                                className={`appearance-none cursor-pointer text-[10px] font-black uppercase tracking-wider px-3 py-1 rounded-full ${styles.pill} border-none outline-none hover:brightness-95 text-center transition-all shadow-sm`}
                            >
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="COMPLIANT">COMPLIANT</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MINOR">MINOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="NC_MAJOR">MAJOR NC</option>
                                <option className="bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value="OFI">OFI</option>
                            </select>
                        </div>
                    </div>

                    {/* EDITABLE EVIDENCE SECTION */}
                    <div className="mb-4 group/evidence">
                        <div className="bg-slate-50 dark:bg-slate-950/50 p-4 rounded-xl border border-slate-100 dark:border-slate-800 relative transition-colors focus-within:border-indigo-300 dark:focus-within:border-indigo-700 focus-within:ring-1 focus-within:ring-indigo-500/20" onClick={e => e.stopPropagation()}>
                            <div className="flex justify-between items-center mb-2">
                                <strong className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider block">Verified Evidence</strong>
                                <span className="text-[9px] text-slate-400 opacity-0 group-hover/evidence:opacity-100 transition-opacity flex items-center gap-1">
                                    <Icon name="FileEdit" size={10}/> Editable (Raw Data)
                                </span>
                            </div>

                            <textarea
                                value={res.evidence}
                                onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)}
                                className="w-full bg-transparent outline-none text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium resize-y min-h-[80px] whitespace-pre-wrap font-mono custom-scrollbar border-l-2 border-transparent focus:border-indigo-400 pl-2 transition-all"
                                placeholder="Evidence content..."
                                spellCheck={false}
                            />
                        </div>
                    </div>

                    <div className="mb-2">
                        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-colors group-focus-within:border-indigo-500 shadow-sm" onClick={e => e.stopPropagation()}>
                            <strong className="text-[10px] font-bold text-purple-600 dark:text-purple-400 uppercase tracking-wider mb-1 block">Auditor Conclusion</strong>
                            <textarea
                                value={res.reason}
                                onChange={(e) => handleUpdateFinding(idx, 'reason', e.target.value)}
                                className="w-full bg-transparent outline-none text-base text-slate-800 dark:text-slate-200 leading-relaxed resize-none h-auto min-h-[60px]"
                                placeholder="Enter conclusion..."
                            />
                        </div>
                    </div>

                    {/* Shadow Review Result */}
                    {reviewText && (
                        <div className="mt-3 p-3 bg-purple-50 dark:bg-purple-900/20 border-l-4 border-purple-400 rounded-r-lg animate-in slide-in-from-top-2">
                            <div className="flex items-center gap-2 mb-1">
                                <Icon name="ShieldEye" size={12} className="text-purple-600"/>
                                <span className="text-[10px] font-bold text-purple-700 dark:text-purple-300 uppercase">AI Reviewer Note</span>
                            </div>
                            <p className="text-xs text-slate-600 dark:text-slate-300 italic leading-relaxed">"{reviewText}"</p>
                        </div>
                    )}

                    {res.suggestion && !reviewText && (
                        <div className="flex gap-2 items-start mt-3 opacity-80 group-hover:opacity-100 transition-opacity">
                            <div className="p-1 bg-amber-100 dark:bg-amber-900/30 rounded-full text-amber-600 dark:text-amber-400 shrink-0">
                                <Icon name="Lightbulb" size={10} />
                            </div>
                            <p className="text-[10px] text-slate-500 dark:text-slate-400 italic leading-tight pt-0.5">{res.suggestion}</p>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up">
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1" ref={findingsContainerRef}>
                {!analysisResult && !isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                        <div className="p-6 bg-slate-100 dark:bg-slate-800 rounded-full mb-4 animate-pulse-slow">
                            <Icon name="Wand2" size={48} className="text-indigo-300 dark:text-indigo-600" />
                        </div>
                        <p className="font-bold">No analysis results yet.</p>
                        <p className="text-xs mt-2">Run analysis from the Audit tab to generate findings.</p>
                    </div>
                )}

                {isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center">
                        <div className="relative w-28 h-28 mb-8">
                            <div className="absolute inset-0 border-4 border-indigo-100 dark:border-indigo-900/50 rounded-full opacity-50"></div>
                            <div className="absolute inset-0 border-t-4 border-indigo-500 rounded-full animate-spin"></div>
                            <div className="absolute inset-4 border-r-4 border-purple-500 rounded-full animate-spin-reverse opacity-70"></div>
                            <div className="absolute inset-0 flex items-center justify-center"><Icon name="BrainCircuit" size={32} className="text-indigo-500 animate-pulse"/></div>
                        </div>
                        <h3 className="text-2xl font-black text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 to-purple-500 animate-pulse mb-3">AI Auditor Working</h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400 font-medium mb-1 bg-white/50 dark:bg-slate-800/50 px-4 py-1 rounded-full shadow-sm">{loadingMessage}</p>
                        <p className="text-xs text-slate-400 font-mono mt-2 opacity-80">{currentAnalyzingClause && `Analyzing Clause: [${currentAnalyzingClause}]`}</p>
                    </div>
                )}

                {analysisResult && (
                    viewMode === 'list' ? (
                        <div className="space-y-4 pb-10">
                            {analysisResult.map((res, idx) => renderFindingCard(res, idx))}
                        </div>
                    ) : (
                        <div className="flex flex-col h-full gap-4">
                            {/* Matrix Header Container - Collapsible */}
                            <div className={`flex-shrink-0 flex flex-col bg-white dark:bg-slate-900 rounded-2xl border ${themeConfig.borderClass.replace('border-', 'border-opacity-30 border-')} border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} dark:border-slate-800 overflow-hidden shadow-depth transition-all duration-300 ease-in-out ${isMatrixCollapsed ? 'h-11 min-h-[44px]' : 'h-auto max-h-[45vh]'}`}>

                                {/* Control Bar */}
                                <div className="flex items-center justify-between px-3 py-2 bg-white/50 dark:bg-slate-900/50 border-b border-gray-50 dark:border-slate-800 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800" onClick={() => setIsMatrixCollapsed(!isMatrixCollapsed)}>
                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                        <Icon name="Grid" size={12}/> Findings Matrix ({Object.keys(groupedFindings).length} Processes)
                                    </span>
                                    <div className="text-slate-400 hover:text-indigo-500 transition-colors">
                                        <Icon name={isMatrixCollapsed ? "ChevronDown" : "ChevronUp"} size={16} />
                                    </div>
                                </div>

                                {/* Matrix Content - Only rendered fully when not collapsed to save DOM/Layout calc, or hidden via CSS for animation */}
                                <div className={`flex flex-col transition-opacity duration-200 ${isMatrixCollapsed ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
                                    {/* UPDATED GRID: [Clause] | [Major] | [Minor] | [OFI] | [Comp] */}
                                    <div className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 p-3 border-b border-gray-100 dark:border-slate-800 ${themeConfig.bgSoft} sticky top-0 z-10 transition-colors duration-500 ease-fluid`}>
                                        <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest text-center">Clause</div>
                                        <div className="text-[10px] font-bold text-red-500 uppercase tracking-widest text-center">Major</div>
                                        <div className="text-[10px] font-bold text-orange-500 uppercase tracking-widest text-center">Minor</div>
                                        <div className="text-[10px] font-bold text-blue-500 uppercase tracking-widest text-center">OFI</div>
                                        <div className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest text-center">Comp</div>
                                    </div>
                                    <div className="overflow-y-auto custom-scrollbar max-h-[40vh] p-2">
                                        {Object.entries(groupedFindings).map(([processName, items]) => {
                                            const isCollapsed = collapsedGroups.has(processName);
                                            const typedItems = items as { finding: AnalysisResult, originalIndex: number }[];
                                            const countNC = typedItems.filter(i => i.finding.status === 'NC_MAJOR' || i.finding.status === 'NC_MINOR').length;

                                            return (
                                                <div key={processName} className="flex flex-col mb-2 rounded-xl border border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 overflow-hidden">
                                                    {/* Group Header */}
                                                    <div 
                                                        className="flex items-center justify-between px-3 py-2 bg-white dark:bg-slate-900 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors"
                                                        onClick={() => toggleGroup(processName)}
                                                    >
                                                        <div className="flex items-center gap-2">
                                                            <Icon name="ChevronDown" size={14} className={`text-slate-400 transition-transform duration-300 ${isCollapsed ? '-rotate-90' : ''}`}/>
                                                            <span className="text-xs font-bold text-indigo-600 dark:text-indigo-300 uppercase tracking-wide truncate max-w-[200px]" title={processName}>
                                                                {processName} 
                                                            </span>
                                                            <span className="text-[10px] text-slate-400 font-normal">({typedItems.length})</span>
                                                        </div>
                                                        {countNC > 0 && <span className="text-[9px] font-bold text-red-500 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded shadow-sm">{countNC} NCs</span>}
                                                    </div>

                                                    {/* Group Items with SCROLLABLE CONTAINER */}
                                                    {!isCollapsed && (
                                                        <div className="max-h-[240px] overflow-y-auto custom-scrollbar divide-y divide-gray-100 dark:divide-slate-800/50 border-t border-gray-100 dark:border-slate-800">
                                                            {typedItems.map(({ finding: item, originalIndex: idx }) => {
                                                                const isSelected = focusedFindingIndex === idx;
                                                                return (
                                                                    <div key={idx} onClick={() => setFocusedFindingIndex(idx)} className={`grid grid-cols-[80px_1fr_1fr_1fr_1fr] gap-1 py-2 cursor-pointer transition-colors ${isSelected ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'hover:bg-slate-100 dark:hover:bg-slate-800/80'}`}>
                                                                        <div className={`flex items-center justify-center h-full w-full text-[10px] font-mono font-bold ${isSelected ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-400'}`}>{item.clauseId}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MAJOR' && <div className="w-4 h-4 rounded bg-red-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Major NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'NC_MINOR' && <div className="w-4 h-4 rounded bg-orange-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Minor NC"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'OFI' && <div className="w-4 h-4 rounded bg-blue-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Opportunity for Improvement"></div>}</div>
                                                                        <div className="flex items-center justify-center h-full w-full">{item.status === 'COMPLIANT' && <div className="w-4 h-4 rounded bg-emerald-500 shadow-md ring-2 ring-white dark:ring-slate-900" title="Compliant"></div>}</div>
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>

                            {/* Detail Panel */}
