        switch (layoutMode) {
            case 'planning': return 'selection:bg-orange-200 selection:text-orange-900 dark:selection:bg-orange-900 dark:selection:text-orange-100 bg-orange-50/80 dark:bg-orange-950/20';
            case 'evidence': return 'selection:bg-blue-200 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100 bg-blue-50/80 dark:bg-blue-950/20';
            case 'findings': return 'selection:bg-purple-200 selection:text-purple-900 dark:selection:bg-purple-900 dark:selection:text-purple-100 bg-purple-50/80 dark:bg-purple-950/20';
            case 'report': return 'selection:bg-emerald-200 selection:text-emerald-900 dark:selection:bg-emerald-900 dark:selection:text-emerald-100 bg-emerald-50/80 dark:bg-emerald-950/20';
            default: return 'selection:bg-indigo-200 selection:text-indigo-900';
        }
    }, [layoutMode]);

    const currentTabConfig = TABS_CONFIG.find(t => t.id === layoutMode) || TABS_CONFIG[0];
    const showProcessBlocker = (!activeProcessId || processes.length === 0) && layoutMode !== 'planning';

    const handleAddKeyWrapper = async () => {
        const status = await addKey(newKeyInput);
        if (status === 'valid') { setNewKeyInput(""); showToast("Success: API Key is Active"); } 
        else if (status === 'quota_exceeded') { setNewKeyInput(""); showToast("Added: Key Quota Exhausted"); } 
        else if (status === 'duplicate') showToast("Info: Key already exists"); 
        else showToast("Failed: Invalid API Key or Network Error");
    };

    const isReadyForAnalysis = useMemo(() => {
        if (!standardKey || !activeProcessId || isAnalyzeLoading) return false;
        // Explicitly type the iterator to MatrixRow[] to avoid 'unknown' error
        const hasMatrixData = Object.values(matrixData).some((rows: MatrixRow[]) => rows.some(r => r.status === 'supplied'));
        const hasGlobalEvidence = evidence && evidence.trim().length > 10;
        return hasMatrixData || hasGlobalEvidence;
    }, [standardKey, activeProcessId, matrixData, evidence, isAnalyzeLoading]);

    // Wrap Analyze with Auto-Switch
    const handleAnalyzeClick = async () => {
        setLayoutMode('findings'); // Auto-switch to see progress
        await handleAnalyze();
    };

    return (
        <MainLayout commandActions={[]} onRestoreSnapshot={restoreSession}>
            {/* Top Bar - Color Synced Border Top */}
            <div className={`flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 transition-colors duration-500 ease-fluid flex justify-between items-center gap-3 border-t-4 ${currentTabConfig.borderClass} ${liquidColorClass.split(' ')[0].replace('bg-', 'bg-opacity-10 ')}`}>
                <div className="flex-1 min-w-0">
                    <TabNavigation 
                        layoutMode={layoutMode} 
                        setLayoutMode={setLayoutMode}
                        isSidebarOpen={isSidebarOpen}
                        sidebarWidth={sidebarWidth}
                    />
                </div>
                <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                    <button onClick={() => toggleModal('recall', true)} className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all border shadow-sm ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600' : 'bg-white dark:bg-slate-800 text-slate-500'}`}>
                        <div className="relative">
                            <Icon name="History" size={18}/>
                            {lastSavedTime && <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5"><span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span></span>}
                        </div>
                        <span className="hidden xl:inline text-xs font-bold">Recall</span>
                    </button>
                    <button onClick={() => { if(confirm("Start New Session?")) { createManualBackup(); resetSession(); showToast("Session Reset."); }}} className="h-10 px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 border border-amber-200 rounded-xl flex items-center justify-center gap-2 hover:bg-amber-100 transition-all shadow-sm">
                        <Icon name="Session4_FilePlus" size={18}/>
                        <span className="hidden md:inline text-xs font-bold">New</span>
                    </button>
                </div>
            </div>

            {/* MAIN CONTENT WRAPPER */}
            <div className={`flex-1 overflow-hidden relative p-2 md:p-4 transition-colors duration-500 ease-fluid ${themeStyles}`}>
                {showProcessBlocker && (
                    <div className="absolute inset-0 z-50 bg-white/80 dark:bg-slate-950/80 backdrop-blur-sm flex flex-col items-center justify-center animate-in fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-floating border border-indigo-100 dark:border-indigo-900 max-w-md text-center">
                            <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/50 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600"><Icon name="Session11_GridAdd" size={32} /></div>
                            <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Process Required</h3>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 leading-relaxed">Define at least one <strong>Process</strong> to begin evidence collection.</p>
                            <div className="flex gap-3 justify-center">
                                <button onClick={() => setLayoutMode('planning')} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg transition-transform active:scale-95">Go to Planning</button>
                            </div>
                        </div>
                    </div>
                )}

                <Suspense fallback={<AINeuralLoader message="Loading View..." />}>
                    {layoutMode === 'planning' && <PlanningView />}

                    {layoutMode === 'evidence' && (
                        <EvidenceView
                            evidence={evidence} setEvidence={setEvidence}
                            uploadedFiles={uploadedFiles} setUploadedFiles={setUploadedFiles}
                            onOcrProcess={() => {}} isOcrLoading={false}
                            onAnalyze={handleAnalyzeClick} 
                            isReadyForAnalysis={isReadyForAnalysis} 
                            isAnalyzeLoading={isAnalyzeLoading} 
                            analyzeTooltip="Run AI Analysis"
                            onExport={handleExport} 
                            evidenceLanguage={evidenceLanguage} setEvidenceLanguage={setEvidenceLanguage}
                            textareaRef={{ current: null }} tags={evidenceTags} onAddTag={addEvidenceTag}
                            selectedClauses={selectedClauses} standards={standards} standardKey={standardKey}
                            matrixData={matrixData} setMatrixData={setMatrixData}
                        />
                    )}

                    {layoutMode === 'findings' && (
                        <FindingsView
                            analysisResult={analysisResult} setAnalysisResult={setAnalysisResult}
                            selectedFindings={selectedFindings} setSelectedFindings={setSelectedFindings}
                            isAnalyzeLoading={isAnalyzeLoading} loadingMessage="Synthesizing findings..." 
                            currentAnalyzingClause={currentAnalyzingClause}
                            viewMode={findingsViewMode} setViewMode={setFindingsViewMode}
                            focusedFindingIndex={focusedFindingIndex} setFocusedFindingIndex={setFocusedFindingIndex}
                            onExport={handleExport} 
                            notesLanguage={notesLanguage} setNotesLanguage={setNotesLanguage}
                        />
                    )}

                    {layoutMode === 'report' && (
                        <ReportView
                            finalReportText={finalReportText} setFinalReportText={setFinalReportText}
                            isReportLoading={isReportLoading} loadingMessage={reportLoadingMessage}
                            templateFileName={reportTemplateName}
                            isTemplateProcessing={isTemplateProcessing}
                            handleTemplateUpload={handleTemplateUpload} 
                            handleGenerateReport={handleGenerateReport}
                            isReadyToSynthesize={!!analysisResult && analysisResult.length > 0} 
                            onExport={handleExport} 
                            exportLanguage={exportLanguage} setExportLanguage={setExportLanguage}
                            analysisResult={analysisResult} // Pass results for Stage Builder
                            generationLogs={generationLogs}
                            progressPercent={progressPercent}
                            selectedFindings={selectedFindings} // PASS SELECTION STATE
                        />
                    )}
                </Suspense>
            </div>

            {/* Modals */}
            <SettingsModal 
                isOpen={modals.settings} onClose={() => toggleModal('settings', false)} 
                apiKeys={apiKeys} newKeyInput={newKeyInput} setNewKeyInput={setNewKeyInput} 
                isCheckingKey={isCheckingKey} handleAddKey={handleAddKeyWrapper}
                activeKeyId={activeKeyId} editingKeyId={null} editLabelInput="" setEditLabelInput={() => {}}
                handleSaveLabel={() => {}} handleStartEdit={() => {}} handleRefreshStatus={refreshKeyStatus} handleDeleteKey={deleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled} toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={modals.addStandard} onClose={() => toggleModal('addStandard', false)}
                onAdd={async (name, file) => {
                    toggleModal('addStandard', false);
                    const newKey = `CUSTOM_${Date.now()}`;
                    if(file) { const text = await processSourceFile(file); setKnowledgeData(text, file.name); }
                    addCustomStandard(newKey, { name, description: "Custom", groups: [] });
                    setStandardKey(newKey);
                }}
            />

            <ReferenceClauseModal
                isOpen={referenceState.isOpen} onClose={() => setReferenceState(prev => ({...prev, isOpen: false}))}
                clause={referenceState.clause} standardName={standards[standardKey]?.name || ""}
                fullText={referenceState.fullText} isLoading={referenceState.isLoading}
                onInsert={(text) => setEvidence(prev => prev + "\n" + text)}
            />

            <ExportProgressModal 
                exportState={exportState} setExportState={setExportState}
                rescueKey={rescueKey} setRescueKey={setRescueKey}
                handleResumeExport={handleResumeExport} isRescuing={isRescuing}
                onClose={() => setExportState(prev => ({ ...prev, isOpen: false }))}
                onSkip={handleSkipExportChunk}
            />
        </MainLayout>
    );
};

export default function App() {
    return (
        <UIProvider>
            <KeyPoolProvider>
                <AuditProvider>
                    <AppContent />
                </AuditProvider>
            </KeyPoolProvider>
        </UIProvider>
    );
}

import React, { useRef, useState, useCallback, useMemo } from 'react';
import { Icon } from '../UI';
import { UploadedFile, EvidenceTag, StandardsData, MatrixRow } from '../../types';
import { EvidenceMatrix, EvidenceMatrixHandle } from './EvidenceMatrix'; 
import { fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';
import { useAudit } from '../../contexts/AuditContext';
import { useVoiceInput } from '../../hooks/useVoiceInput';
import { ProcessHeader } from './evidence/ProcessHeader';
import { ActionToolbar } from './evidence/ActionToolbar';
import { useReferenceLookup } from '../../hooks/useReferenceLookup'; 
import { TABS_CONFIG } from '../../constants';

interface EvidenceViewProps {
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    uploadedFiles: UploadedFile[];
    setUploadedFiles: React.Dispatch<React.SetStateAction<UploadedFile[]>>;
    onOcrProcess: () => void;
    isOcrLoading: boolean;
    onAnalyze: () => void;
    isReadyForAnalysis: boolean;
    isAnalyzeLoading: boolean;
    analyzeTooltip: string;
    onExport: (type: 'evidence', lang: 'en' | 'vi') => void;
    evidenceLanguage: 'en' | 'vi';
    setEvidenceLanguage: (lang: 'en' | 'vi') => void;
    textareaRef: React.RefObject<HTMLTextAreaElement | null>;
    tags?: EvidenceTag[];
    onAddTag?: (tag: EvidenceTag) => void;
    selectedClauses?: string[]; // Deprecated for View logic, kept for interface compat
    standards?: StandardsData;
    standardKey?: string;
    matrixData?: Record<string, MatrixRow[]>;
    setMatrixData?: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
}

export const EvidenceView: React.FC<EvidenceViewProps> = ({
    evidence, setEvidence, uploadedFiles, setUploadedFiles,
    isOcrLoading, onAnalyze, isReadyForAnalysis,
    isAnalyzeLoading, analyzeTooltip, evidenceLanguage, setEvidenceLanguage,
    onExport,
    selectedClauses = [], standards, standardKey, matrixData, setMatrixData
}) => {
    const { activeProcess, activeProcessId, setActiveProcessId, processes, addInterviewee, removeInterviewee } = useAudit();

    // UI State
    const [isDragging, setIsDragging] = useState(false);
    const [isMatrixProcessing, setIsMatrixProcessing] = useState(false);

    // Refs
    const fileTargetRef = useRef<Record<string, { clauseId: string, rowId: string }>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);
    const matrixRef = useRef<EvidenceMatrixHandle>(null);

    // Lookup Hook
    const handleLookup = useReferenceLookup();

    // Computed: STRICT ISOLATION MODE
    // CRITICAL FIX: Do NOT merge with global `selectedClauses`. 
    // The Audit View must ONLY reflect what is inside the active process's `matrixData`.
    // Merging global state caused "data bleeding" where clauses from Process A would appear in Process B.
    const effectiveSelectedClauses = useMemo(() => {
        if (!matrixData) return [];
        const activeKeys = Object.keys(matrixData);
        // Sort keys naturally (e.g. 4.1, 4.2, 4.10) to maintain document structure
        return activeKeys.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
    }, [matrixData]);

    // Color Theme Sync
    const themeConfig = TABS_CONFIG.find(t => t.id === 'evidence')!;

    // --- LOGIC: Voice ---
    const handleVoiceResult = useCallback((text: string) => {
        if (text && matrixRef.current) {
            // Safety check: Ensure row is active (handled by matrixRef generally but good to verify)
            matrixRef.current.handleExternalDictation(text);
        } else {
            alert("Please select a Requirement row in the Matrix first.");
        }
    }, []);

    const { isListening, toggleListening } = useVoiceInput(evidenceLanguage, handleVoiceResult);

    // --- LOGIC: Files ---
    const processNewFiles = useCallback((files: File[], targetOverride?: { clauseId: string, rowId: string }) => {
        const target = targetOverride || matrixRef.current?.getActiveRow();
        if (!target) {
            alert("Please click/focus on a specific Requirement row to attach files.");
            return;
        }

        const newFiles = files.map(f => {
            const id = Math.random().toString(36).substr(2, 9);
            fileTargetRef.current[id] = target;
            return { id, file: f, status: 'pending' as const };
        });
        setUploadedFiles(prev => [...prev, ...newFiles]);
    }, [setUploadedFiles]);

    const handleRemoveFile = useCallback((fileId: string) => {
        setUploadedFiles(prev => prev.filter(f => f.id !== fileId));
        delete fileTargetRef.current[fileId];
    }, [setUploadedFiles]);

    const handleMatrixOcrProcess = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;

        setIsMatrixProcessing(true);

        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));

                let text = "";
                if (fileEntry.file.type.startsWith('image/')) {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await generateOcrContent("Transcribe text.", base64, fileEntry.file.type);
                } else if (fileEntry.file.type === 'application/pdf') {
                     text = "[PDF Content extracted via OCR would go here - System limitation]"; 
                } else {
                    text = await fileEntry.file.text();
                }

                if (text && matrixRef.current) {
                    const target = fileTargetRef.current[fileEntry.id];
                    if (target) {
                        const header = `[File: ${fileEntry.file.name}]`;
                        matrixRef.current.insertEvidence(target.clauseId, target.rowId, `${header}\n${text}`);

                        // AUTO-REMOVE SUCCESSFUL FILE
                        setUploadedFiles(prev => prev.filter(f => f.id !== fileEntry.id));
                    }
                }
            } catch (error: any) {
                console.error("Matrix OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsMatrixProcessing(false);
    }, [uploadedFiles, setUploadedFiles]);

    // --- LOGIC: Drag & Drop ---
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); }, []);
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            processNewFiles(Array.from(e.dataTransfer.files));
        }
    }, [processNewFiles]);

    return (
        <div className="h-full flex flex-col gap-2 md:gap-3 animate-fade-in-up relative p-1">

            <ProcessHeader 
                processes={processes}
                activeProcessId={activeProcessId}
                activeProcess={activeProcess}
                setActiveProcessId={(id) => setActiveProcessId(id)}
                addInterviewee={addInterviewee}
                removeInterviewee={removeInterviewee}
            />

            <div className="flex-1 flex flex-col gap-2 min-h-0 relative">
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*,application/pdf,text/plain" multiple onChange={(e) => e.target.files && processNewFiles(Array.from(e.target.files))} />

                <div
                    className={`flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} overflow-hidden flex flex-row relative group transition-all duration-500 ease-fluid dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_4px_6px_-1px_rgba(0,0,0,0.5)] ${isDragging ? `${themeConfig.borderClass} ring-4 ring-blue-500/20 bg-blue-50/10` : 'border-gray-100 dark:border-transparent'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                >
                    {isDragging && (
                        <div className="absolute inset-0 bg-blue-500/10 backdrop-blur-[2px] z-50 flex flex-col items-center justify-center pointer-events-none animate-in fade-in zoom-in-95 duration-200">
                            <div className="p-6 rounded-full bg-white dark:bg-slate-900 shadow-2xl border-4 border-dashed border-blue-500">
                                <Icon name="UploadCloud" size={48} className="text-blue-600 animate-bounce" />
                            </div>
                            <h3 className="mt-4 text-xl font-black text-blue-700 dark:text-blue-400 uppercase tracking-widest">Drop Files to Active Row</h3>
                        </div>
                    )}

                    {standards && standardKey && standards[standardKey] && matrixData && setMatrixData ? (
                        effectiveSelectedClauses.length > 0 ? (
                            <div className="flex-1 w-full h-full p-1">
                                <EvidenceMatrix 
                                    ref={matrixRef}
                                    standard={standards[standardKey]}
                                    selectedClauses={effectiveSelectedClauses}
                                    matrixData={matrixData}
                                    setMatrixData={setMatrixData}
                                    onPasteFiles={processNewFiles}
                                    uploadedFiles={uploadedFiles}
                                    onRemoveFile={handleRemoveFile}
                                    onLookup={handleLookup} // Connect Lookup
                                />
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-slate-400 bg-gray-50/20 dark:bg-slate-900/50">
                                <div className="p-6 bg-white dark:bg-slate-800 rounded-full shadow-lg mb-4">
                                    <Icon name="LayoutList" size={48} className="text-indigo-200 dark:text-slate-600" />
                                </div>
                                <h3 className="text-lg font-bold text-slate-600 dark:text-slate-300">No Clauses Planned</h3>
                                <p className="text-xs text-slate-400 mt-2 max-w-xs text-center">
                                    Go to the <strong>Planning</strong> tab to select which clauses apply to the <strong>{activeProcess?.name || "Active"}</strong> process.
                                </p>
                            </div>
                        )
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
                            <Icon name="LayoutList" size={48} className="mb-4 opacity-30" />
                            <p>Please select a Standard to view the Matrix.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* ACTION & EXPORT FOOTER */}
            <div className="flex-shrink-0 flex flex-row items-center justify-between gap-2 md:gap-3 w-full pt-1">
                {/* Left Side: Input Tools */}
                <div className="flex-1 min-w-0">
                    <ActionToolbar 
                        uploadedFiles={uploadedFiles}
                        onOcrProcess={handleMatrixOcrProcess}
                        isOcrLoading={isOcrLoading}
                        isProcessing={isMatrixProcessing}
                        toggleListening={toggleListening}
                        isListening={isListening}
                        triggerFileUpload={() => fileInputRef.current?.click()}
                        onAnalyze={onAnalyze}
                        isReadyForAnalysis={isReadyForAnalysis}
                        isAnalyzeLoading={isAnalyzeLoading}
                    />
                </div>

                {/* Right Side: Export with Language Toggle */}
                <button 
                    onClick={() => onExport('evidence', evidenceLanguage)} 
                    className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm whitespace-nowrap dark:shadow-md"
                    title="Export Raw Evidence"
                >
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container">
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('en'); }} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('vi'); }} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, useMemo, useRef } from 'react';
import { StandardsData, AuditInfo, AuditProcess, Standard, MatrixRow, EvidenceTag, AnalysisResult, PrivacySettings } from '../types';
import { DEFAULT_AUDIT_INFO, STANDARDS_DATA, INITIAL_EVIDENCE } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Privacy
    privacySettings: PrivacySettings;
    setPrivacySettings: React.Dispatch<React.SetStateAction<PrivacySettings>>;

    // Process Management
    processes: AuditProcess[];
    activeProcessId: string | null;
    activeProcess: AuditProcess | undefined;
    setActiveProcessId: (id: string | null) => void;
    addProcess: (name: string) => void;
    renameProcess: (id: string, name: string) => void;
    deleteProcess: (id: string) => void;
    batchUpdateProcessClauses: (updates: { processId: string, clauses: string[] }[]) => void;
    toggleProcessClause: (processId: string, clauseId: string) => void; 

    // Interviewee Management
    addInterviewee: (name: string) => void;
    removeInterviewee: (name: string) => void;

    // Active Data
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections (Global/Legacy - mostly for sidebar highlighting)
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

const DEFAULT_PRIVACY: PrivacySettings = {
    maskCompany: true,
    maskSmo: true,
    maskPeople: true,
    maskEmail: true,
    maskPhone: true,
    maskAddress: true,
    maskIP: true
};

export const AuditProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [privacySettings, setPrivacySettings] = useState<PrivacySettings>(DEFAULT_PRIVACY);

    // Processes (Start Empty)
    const [processes, setProcesses] = useState<AuditProcess[]>([]);
    const [activeProcessId, setActiveProcessId] = useState<string | null>(null);

    // Active View Data (Synced with Active Process)
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    // --- REFS FOR SYNC SAFETY ---
    // Critical: We use a ref to track activeProcessId inside the Save Effect.
    // This prevents the Save Effect from running immediately when activeProcessId changes (which would save OLD data to NEW process).
    const activeProcessIdRef = useRef(activeProcessId);

    const standards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);

    // Safe fallback
    const activeProcess = useMemo(() => processes.find(p => p.id === activeProcessId), [processes, activeProcessId]);

    // --- SYNC EFFECTS ---

    // 1. Update Ref when ID changes (Sync Layer)
    useEffect(() => {
        activeProcessIdRef.current = activeProcessId;
    }, [activeProcessId]);

    // 2. Load Process Data (Read Layer)
    // When activeProcessId changes, we MUST load the data from the process into the local view state.
    useEffect(() => {
        if (!activeProcessId) {
            setEvidence("");
            setMatrixData({});
            setEvidenceTags([]);
            return;
        }

        setProcesses(currentProcesses => {
            const target = currentProcesses.find(p => p.id === activeProcessId);
            if (target) {
                // Populate local state from store
                setEvidence(target.evidence || "");
                setMatrixData(target.matrixData || {});
                setEvidenceTags(target.evidenceTags || []);
            }
            return currentProcesses;
        });
    }, [activeProcessId]);

    // 3. Save View Data (Write Layer)
    // CRITICAL FIX: This effect MUST NOT depend on `activeProcessId`.
    // It should only run when the actual content (`evidence`, `matrixData`) changes.
    // It uses the Ref to know where to save.
    useEffect(() => {
        const currentId = activeProcessIdRef.current;
        if (!currentId) return;

        setProcesses(prev => prev.map(p => {
            if (p.id === currentId) {
                // Only update if something actually changed to avoid cycles
                if (p.evidence !== evidence || p.matrixData !== matrixData || p.evidenceTags !== evidenceTags) {
                    return { ...p, evidence, matrixData, evidenceTags };
                }
            }
            return p;
        }));
    }, [evidence, matrixData, evidenceTags]); // NO activeProcessId dependency here!

    // --- ACTIONS ---

    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        if (standardKey === key) setStandardKey("");
    };

    const addProcess = (name: string) => {
        const newId = `proc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;
        const newProcess = { 
            id: newId, 
            name, 
            evidence: "", 
            interviewees: [],
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [] 
        };
        setProcesses(prev => [...prev, newProcess]);
        setActiveProcessId(newId);
    };

    const renameProcess = (id: string, name: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    };

    const deleteProcess = (idToDelete: string) => {
        if (activeProcessId === idToDelete) {
            setProcesses(prev => {
                const remaining = prev.filter(p => p.id !== idToDelete);
                const nextId = remaining.length > 0 ? remaining[0].id : null;
                setActiveProcessId(nextId);
                return remaining;
            });
        } else {
            setProcesses(prev => prev.filter(p => p.id !== idToDelete));
        }
    };

    const findClauseInStandard = (cid: string, standard: Standard | undefined): any => {
        if (!standard) return null;
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const findRecursive = (id: string, list: any[]): any => {
            for (const c of list) {
                if (c.id === id) return c;
                if (c.subClauses) {
                    const found = findRecursive(id, c.subClauses);
                    if (found) return found;
                }
            }
            return null;
        };
        return findRecursive(cid, allClauses);
    };

    const batchUpdateProcessClauses = (updates: { processId: string, clauses: string[] }[]) => {
        setProcesses(prev => prev.map(p => {
            const update = updates.find(u => u.processId === p.id);
            if (update) {
                const newMatrixData = { ...p.matrixData };
                const standard = standards[standardKey];

                update.clauses.forEach(clauseId => {
                    if (!newMatrixData[clauseId]) {
                        const clause = findClauseInStandard(clauseId, standard);
                        const desc = clause?.description || "Requirement";
                        newMatrixData[clauseId] = [{
                            id: `${clauseId}_req_0`,
                            requirement: desc,
                            evidenceInput: "",
                            status: 'pending'
                        }];
                    }
                });
                return { ...p, matrixData: newMatrixData };
            }
            return p;
        }));

        const activeUpdate = updates.find(u => u.processId === activeProcessId);
        if (activeUpdate) {
             setMatrixData(prev => {
                 const next = { ...prev };
                 const standard = standards[standardKey];
                 activeUpdate.clauses.forEach(cid => {
                     if(!next[cid]) {
                         const c = findClauseInStandard(cid, standard);
                         const desc = c?.description || "Requirement";
                         next[cid] = [{ id: `${cid}_req_0`, requirement: desc, evidenceInput: "", status: 'pending' }];
                     }
                 });
                 return next;
             });
        }
    };

    const toggleProcessClause = (processId: string, clauseId: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id !== processId) return p;

            const newMatrixData = { ...p.matrixData };
            if (newMatrixData[clauseId]) {
                delete newMatrixData[clauseId];
            } else {
                const standard = standards[standardKey];
                const clause = findClauseInStandard(clauseId, standard);
                const desc = clause?.description || "Requirement";

                newMatrixData[clauseId] = [{
                    id: `${clauseId}_req_0`,
                    requirement: desc,
                    evidenceInput: "",
                    status: 'pending'
                }];
            }
            return { ...p, matrixData: newMatrixData };
        }));

        if (activeProcessId === processId) {
            setMatrixData(prev => {
                const next = { ...prev };
                if (next[clauseId]) {
                    delete next[clauseId];
                } else {
                    const standard = standards[standardKey];
                    const clause = findClauseInStandard(clauseId, standard);
                    const desc = clause?.description || "Requirement";
                    next[clauseId] = [{
                        id: `${clauseId}_req_0`,
                        requirement: desc,
                        evidenceInput: "",
                        status: 'pending'
                    }];
                }
                return next;
            });
        }
    };

    const addInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (!p.interviewees.includes(name)) {
                    return { ...p, interviewees: [...p.interviewees, name] };
                }
            }
            return p;
        }));
    };

    const removeInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                return { ...p, interviewees: p.interviewees.filter(i => i !== name) };
            }
            return p;
        }));
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) { console.error(e); }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteDocument(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setProcesses([]);
        setActiveProcessId(null);
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        setPrivacySettings(DEFAULT_PRIVACY);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
        if (data.privacySettings) setPrivacySettings(data.privacySettings);

        if (data.processes && data.processes.length > 0) {
            setProcesses(data.processes);
            if(data.activeProcessId) setActiveProcessId(data.activeProcessId);
        } else if (data.scopes && data.scopes.length > 0) {
             const migrated = data.scopes.map((s: any) => ({
                 ...s,
                 interviewees: [] 
             }));
             setProcesses(migrated);
             if(data.activeScopeId) setActiveProcessId(data.activeScopeId);
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    // Memoize the value to prevent re-renders in consumers
    const contextValue = useMemo(() => ({
        standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
        auditInfo, setAuditInfo,
        privacySettings, setPrivacySettings,
        processes, activeProcessId, activeProcess, setActiveProcessId, addProcess, renameProcess, deleteProcess, batchUpdateProcessClauses, toggleProcessClause,
        addInterviewee, removeInterviewee,
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, setSelectedClauses,
        knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
        analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
        resetSession, restoreSession
    }), [
        standards, standardKey, customStandards, auditInfo, privacySettings,
        processes, activeProcessId, activeProcess,
        evidence, matrixData, evidenceTags,
        selectedClauses, knowledgeBase, knowledgeFileName,
        analysisResult, selectedFindings, finalReportText
    ]);

    return (
        <AuditContext.Provider value={contextValue}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { useRef, useState, useCallback, useMemo } from 'react';
import { Icon } from '../UI';
import { UploadedFile, EvidenceTag, StandardsData, MatrixRow } from '../../types';
import { EvidenceMatrix, EvidenceMatrixHandle } from './EvidenceMatrix'; 
import { fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';
import { useAudit } from '../../contexts/AuditContext';
import { useVoiceInput } from '../../hooks/useVoiceInput';
import { ProcessHeader } from './evidence/ProcessHeader';
import { ActionToolbar } from './evidence/ActionToolbar';
import { useReferenceLookup } from '../../hooks/useReferenceLookup'; 
import { TABS_CONFIG } from '../../constants';

interface EvidenceViewProps {
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    uploadedFiles: UploadedFile[];
    setUploadedFiles: React.Dispatch<React.SetStateAction<UploadedFile[]>>;
    onOcrProcess: () => void;
    isOcrLoading: boolean;
    onAnalyze: () => void;
    isReadyForAnalysis: boolean;
    isAnalyzeLoading: boolean;
    analyzeTooltip: string;
    onExport: (type: 'evidence', lang: 'en' | 'vi') => void;
    evidenceLanguage: 'en' | 'vi';
    setEvidenceLanguage: (lang: 'en' | 'vi') => void;
    textareaRef: React.RefObject<HTMLTextAreaElement | null>;
    tags?: EvidenceTag[];
    onAddTag?: (tag: EvidenceTag) => void;
    selectedClauses?: string[]; // Deprecated for View logic, kept for interface compat
    standards?: StandardsData;
    standardKey?: string;
    matrixData?: Record<string, MatrixRow[]>;
    setMatrixData?: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
}

export const EvidenceView: React.FC<EvidenceViewProps> = ({
    evidence, setEvidence, uploadedFiles, setUploadedFiles,
    isOcrLoading, onAnalyze, isReadyForAnalysis,
    isAnalyzeLoading, analyzeTooltip, evidenceLanguage, setEvidenceLanguage,
    onExport,
    // Note: We deliberately ignore the passed `selectedClauses` prop here to prevent global state from bleeding into process context.
    standards, standardKey, matrixData, setMatrixData
}) => {
    const { activeProcess, activeProcessId, setActiveProcessId, processes, addInterviewee, removeInterviewee } = useAudit();

    // UI State
    const [isDragging, setIsDragging] = useState(false);
    const [isMatrixProcessing, setIsMatrixProcessing] = useState(false);

    // Refs
    const fileTargetRef = useRef<Record<string, { clauseId: string, rowId: string }>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);
    const matrixRef = useRef<EvidenceMatrixHandle>(null);

    // Lookup Hook
    const handleLookup = useReferenceLookup();

    // Computed: STRICT ISOLATION MODE
    // CRITICAL FIX: Do NOT use global `selectedClauses`. 
    // The Audit View must ONLY reflect what is inside the active process's `matrixData`.
    // Merging global state caused "data bleeding" where clauses from Process A would appear in Process B.
    const effectiveSelectedClauses = useMemo(() => {
        if (!matrixData) return [];
        const activeKeys = Object.keys(matrixData);
        // Sort keys naturally (e.g. 4.1, 4.2, 4.10) to maintain document structure
        return activeKeys.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
    }, [matrixData]);

    // Color Theme Sync
    const themeConfig = TABS_CONFIG.find(t => t.id === 'evidence')!;

    // --- LOGIC: Voice ---
    const handleVoiceResult = useCallback((text: string) => {
        if (text && matrixRef.current) {
            // Safety check: Ensure row is active (handled by matrixRef generally but good to verify)
            matrixRef.current.handleExternalDictation(text);
        } else {
            alert("Please select a Requirement row in the Matrix first.");
        }
    }, []);

    const { isListening, toggleListening } = useVoiceInput(evidenceLanguage, handleVoiceResult);

    // --- LOGIC: Files ---
    const processNewFiles = useCallback((files: File[], targetOverride?: { clauseId: string, rowId: string }) => {
        const target = targetOverride || matrixRef.current?.getActiveRow();
        if (!target) {
            alert("Please click/focus on a specific Requirement row to attach files.");
            return;
        }

        const newFiles = files.map(f => {
            const id = Math.random().toString(36).substr(2, 9);
            fileTargetRef.current[id] = target;
            return { id, file: f, status: 'pending' as const };
        });
        setUploadedFiles(prev => [...prev, ...newFiles]);
    }, [setUploadedFiles]);

    const handleRemoveFile = useCallback((fileId: string) => {
        setUploadedFiles(prev => prev.filter(f => f.id !== fileId));
        delete fileTargetRef.current[fileId];
    }, [setUploadedFiles]);

    const handleMatrixOcrProcess = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;

        setIsMatrixProcessing(true);

        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));

                let text = "";
                if (fileEntry.file.type.startsWith('image/')) {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await generateOcrContent("Transcribe text.", base64, fileEntry.file.type);
                } else if (fileEntry.file.type === 'application/pdf') {
                     text = "[PDF Content extracted via OCR would go here - System limitation]"; 
                } else {
                    text = await fileEntry.file.text();
                }

                if (text && matrixRef.current) {
                    const target = fileTargetRef.current[fileEntry.id];
                    if (target) {
                        const header = `[File: ${fileEntry.file.name}]`;
                        matrixRef.current.insertEvidence(target.clauseId, target.rowId, `${header}\n${text}`);

                        // AUTO-REMOVE SUCCESSFUL FILE
                        setUploadedFiles(prev => prev.filter(f => f.id !== fileEntry.id));
                    }
                }
            } catch (error: any) {
                console.error("Matrix OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsMatrixProcessing(false);
    }, [uploadedFiles, setUploadedFiles]);

    // --- LOGIC: Drag & Drop ---
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); }, []);
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            processNewFiles(Array.from(e.dataTransfer.files));
        }
    }, [processNewFiles]);

    return (
        <div className="h-full flex flex-col gap-2 md:gap-3 animate-fade-in-up relative p-1">

            <ProcessHeader 
                processes={processes}
                activeProcessId={activeProcessId}
                activeProcess={activeProcess}
                setActiveProcessId={(id) => setActiveProcessId(id)}
                addInterviewee={addInterviewee}
                removeInterviewee={removeInterviewee}
            />

            <div className="flex-1 flex flex-col gap-2 min-h-0 relative">
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*,application/pdf,text/plain" multiple onChange={(e) => e.target.files && processNewFiles(Array.from(e.target.files))} />

                <div
                    className={`flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-t-4 border-t-${themeConfig.borderClass.replace('border-', '')} overflow-hidden flex flex-row relative group transition-all duration-500 ease-fluid dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_4px_6px_-1px_rgba(0,0,0,0.5)] ${isDragging ? `${themeConfig.borderClass} ring-4 ring-blue-500/20 bg-blue-50/10` : 'border-gray-100 dark:border-transparent'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                >
                    {isDragging && (
                        <div className="absolute inset-0 bg-blue-500/10 backdrop-blur-[2px] z-50 flex flex-col items-center justify-center pointer-events-none animate-in fade-in zoom-in-95 duration-200">
                            <div className="p-6 rounded-full bg-white dark:bg-slate-900 shadow-2xl border-4 border-dashed border-blue-500">
                                <Icon name="UploadCloud" size={48} className="text-blue-600 animate-bounce" />
                            </div>
                            <h3 className="mt-4 text-xl font-black text-blue-700 dark:text-blue-400 uppercase tracking-widest">Drop Files to Active Row</h3>
                        </div>
                    )}

                    {standards && standardKey && standards[standardKey] && matrixData && setMatrixData ? (
                        effectiveSelectedClauses.length > 0 ? (
                            <div className="flex-1 w-full h-full p-1">
                                <EvidenceMatrix 
                                    ref={matrixRef}
                                    standard={standards[standardKey]}
                                    selectedClauses={effectiveSelectedClauses}
                                    matrixData={matrixData}
                                    setMatrixData={setMatrixData}
                                    onPasteFiles={processNewFiles}
                                    uploadedFiles={uploadedFiles}
                                    onRemoveFile={handleRemoveFile}
                                    onLookup={handleLookup} // Connect Lookup
                                />
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-slate-400 bg-gray-50/20 dark:bg-slate-900/50">
                                <div className="p-6 bg-white dark:bg-slate-800 rounded-full shadow-lg mb-4">
                                    <Icon name="LayoutList" size={48} className="text-indigo-200 dark:text-slate-600" />
                                </div>
                                <h3 className="text-lg font-bold text-slate-600 dark:text-slate-300">No Clauses Planned</h3>
                                <p className="text-xs text-slate-400 mt-2 max-w-xs text-center">
                                    Go to the <strong>Planning</strong> tab to select which clauses apply to the <strong>{activeProcess?.name || "Active"}</strong> process.
                                </p>
                            </div>
                        )
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
                            <Icon name="LayoutList" size={48} className="mb-4 opacity-30" />
                            <p>Please select a Standard to view the Matrix.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* ACTION & EXPORT FOOTER */}
            <div className="flex-shrink-0 flex flex-row items-center justify-between gap-2 md:gap-3 w-full pt-1">
                {/* Left Side: Input Tools */}
                <div className="flex-1 min-w-0">
                    <ActionToolbar 
                        uploadedFiles={uploadedFiles}
                        onOcrProcess={handleMatrixOcrProcess}
                        isOcrLoading={isOcrLoading}
                        isProcessing={isMatrixProcessing}
                        toggleListening={toggleListening}
                        isListening={isListening}
                        triggerFileUpload={() => fileInputRef.current?.click()}
                        onAnalyze={onAnalyze}
                        isReadyForAnalysis={isReadyForAnalysis}
                        isAnalyzeLoading={isAnalyzeLoading}
                    />
                </div>

                {/* Right Side: Export with Language Toggle */}
                <button 
                    onClick={() => onExport('evidence', evidenceLanguage)} 
                    className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm whitespace-nowrap dark:shadow-md"
                    title="Export Raw Evidence"
                >
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container">
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('en'); }} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('vi'); }} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, useMemo, useRef } from 'react';
import { StandardsData, AuditInfo, AuditProcess, Standard, MatrixRow, EvidenceTag, AnalysisResult, PrivacySettings } from '../types';
import { DEFAULT_AUDIT_INFO, STANDARDS_DATA, INITIAL_EVIDENCE } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Privacy
    privacySettings: PrivacySettings;
    setPrivacySettings: React.Dispatch<React.SetStateAction<PrivacySettings>>;

    // Process Management
    processes: AuditProcess[];
    activeProcessId: string | null;
    activeProcess: AuditProcess | undefined;
    setActiveProcessId: (id: string | null) => void;
    addProcess: (name: string) => void;
    renameProcess: (id: string, name: string) => void;
    deleteProcess: (id: string) => void;
    batchUpdateProcessClauses: (updates: { processId: string, clauses: string[] }[]) => void;
    toggleProcessClause: (processId: string, clauseId: string) => void; 

    // Interviewee Management
    addInterviewee: (name: string) => void;
    removeInterviewee: (name: string) => void;

    // Active Data
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections (Global/Legacy - mostly for sidebar highlighting)
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

const DEFAULT_PRIVACY: PrivacySettings = {
    maskCompany: true,
    maskSmo: true,
    maskPeople: true,
    maskEmail: true,
    maskPhone: true,
    maskAddress: true,
    maskIP: true
};

export const AuditProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [privacySettings, setPrivacySettings] = useState<PrivacySettings>(DEFAULT_PRIVACY);

    // Processes (Start Empty)
    const [processes, setProcesses] = useState<AuditProcess[]>([]);
    const [activeProcessId, setActiveProcessId] = useState<string | null>(null);

    // Active View Data (Synced with Active Process)
    // We use `loadedProcessId` to track which process owns the current `evidence` and `matrixData` in state.
    // This prevents race conditions where we might save data from Process A into Process B during a switch.
    const [loadedProcessId, setLoadedProcessId] = useState<string | null>(null);

    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    const standards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);

    // Safe fallback
    const activeProcess = useMemo(() => processes.find(p => p.id === activeProcessId), [processes, activeProcessId]);

    // Use a ref for processes to access them in effects without causing dependency loops
    const processesRef = useRef(processes);
    useEffect(() => { processesRef.current = processes; }, [processes]);

    // --- SYNC EFFECTS ---

    // 1. Load Process Data (Read Layer)
    // This runs when the user selects a different process.
    useEffect(() => {
        // If we deselected, clear everything
        if (!activeProcessId) {
            setEvidence("");
            setMatrixData({});
            setEvidenceTags([]);
            setLoadedProcessId(null);
            return;
        }

        // Do not reload if we are already loaded (avoids spurious resets)
        if (activeProcessId === loadedProcessId) return;

        const target = processesRef.current.find(p => p.id === activeProcessId);
        if (target) {
            // CRITICAL: We set the loaded ID *simultaneously* with the data.
            // This ensures that any subsequent "Save" effect sees consistent state.
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
            setLoadedProcessId(activeProcessId);
        } else {
            // Fallback if ID invalid
            setLoadedProcessId(null);
        }
    }, [activeProcessId, loadedProcessId]); 

    // 2. Save View Data (Write Layer)
    // This runs whenever the local view data changes (user typing).
    // CRITICAL FIX: We ONLY save to `loadedProcessId`. We do NOT use `activeProcessId` here.
    // If `activeProcessId` changed but `loadedProcessId` hasn't updated yet (race condition),
    // this effect will effectively pause or save to the OLD process (which is safe),
    // rather than overwriting the NEW process with OLD data.
    useEffect(() => {
        if (!loadedProcessId) return;

        setProcesses(prev => prev.map(p => {
            if (p.id === loadedProcessId) {
                // Optimization: Only update reference if data actually changed
                if (p.evidence !== evidence || p.matrixData !== matrixData || p.evidenceTags !== evidenceTags) {
                    return { ...p, evidence, matrixData, evidenceTags };
                }
            }
            return p;
        }));
    }, [evidence, matrixData, evidenceTags, loadedProcessId]);

    // --- ACTIONS ---

    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        if (standardKey === key) setStandardKey("");
    };

    const addProcess = (name: string) => {
        const newId = `proc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;
        const newProcess = { 
            id: newId, 
            name, 
            evidence: "", 
            interviewees: [],
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [] 
        };
        setProcesses(prev => [...prev, newProcess]);
        setActiveProcessId(newId);
    };

    const renameProcess = (id: string, name: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    };

    const deleteProcess = (idToDelete: string) => {
        if (activeProcessId === idToDelete) {
            setProcesses(prev => {
                const remaining = prev.filter(p => p.id !== idToDelete);
                const nextId = remaining.length > 0 ? remaining[0].id : null;
                setActiveProcessId(nextId);
                return remaining;
            });
        } else {
            setProcesses(prev => prev.filter(p => p.id !== idToDelete));
        }
    };

    const findClauseInStandard = (cid: string, standard: Standard | undefined): any => {
        if (!standard) return null;
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const findRecursive = (id: string, list: any[]): any => {
            for (const c of list) {
                if (c.id === id) return c;
                if (c.subClauses) {
                    const found = findRecursive(id, c.subClauses);
                    if (found) return found;
                }
            }
            return null;
        };
        return findRecursive(cid, allClauses);
    };

    const batchUpdateProcessClauses = (updates: { processId: string, clauses: string[] }[]) => {
        setProcesses(prev => prev.map(p => {
            const update = updates.find(u => u.processId === p.id);
            if (update) {
                const newMatrixData = { ...p.matrixData };
                const standard = standards[standardKey];

                update.clauses.forEach(clauseId => {
                    if (!newMatrixData[clauseId]) {
                        const clause = findClauseInStandard(clauseId, standard);
                        const desc = clause?.description || "Requirement";
                        newMatrixData[clauseId] = [{
                            id: `${clauseId}_req_0`,
                            requirement: desc,
                            evidenceInput: "",
                            status: 'pending'
                        }];
                    }
                });
                return { ...p, matrixData: newMatrixData };
            }
            return p;
        }));

        // If we updated the currently loaded process, we must also update local state to reflect changes
        // This is a special case: External modification of the ACTIVE process's structure.
        const activeUpdate = updates.find(u => u.processId === loadedProcessId);
        if (activeUpdate) {
             setMatrixData(prev => {
                 const next = { ...prev };
                 const standard = standards[standardKey];
                 activeUpdate.clauses.forEach(cid => {
                     if(!next[cid]) {
                         const c = findClauseInStandard(cid, standard);
                         const desc = c?.description || "Requirement";
                         next[cid] = [{ id: `${cid}_req_0`, requirement: desc, evidenceInput: "", status: 'pending' }];
                     }
                 });
                 return next;
             });
        }
    };

    const toggleProcessClause = (processId: string, clauseId: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id !== processId) return p;

            const newMatrixData = { ...p.matrixData };
            if (newMatrixData[clauseId]) {
                delete newMatrixData[clauseId];
            } else {
                const standard = standards[standardKey];
                const clause = findClauseInStandard(clauseId, standard);
                const desc = clause?.description || "Requirement";

                newMatrixData[clauseId] = [{
                    id: `${clauseId}_req_0`,
                    requirement: desc,
                    evidenceInput: "",
                    status: 'pending'
                }];
            }
            return { ...p, matrixData: newMatrixData };
        }));

        // Sync local state if we modified the currently loaded process
        if (loadedProcessId === processId) {
            setMatrixData(prev => {
                const next = { ...prev };
                if (next[clauseId]) {
                    delete next[clauseId];
                } else {
                    const standard = standards[standardKey];
                    const clause = findClauseInStandard(clauseId, standard);
                    const desc = clause?.description || "Requirement";
                    next[clauseId] = [{
                        id: `${clauseId}_req_0`,
                        requirement: desc,
                        evidenceInput: "",
                        status: 'pending'
                    }];
                }
                return next;
            });
        }
    };

    const addInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (!p.interviewees.includes(name)) {
                    return { ...p, interviewees: [...p.interviewees, name] };
                }
            }
            return p;
        }));
    };

    const removeInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                return { ...p, interviewees: p.interviewees.filter(i => i !== name) };
            }
            return p;
        }));
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) { console.error(e); }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteDocument(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setProcesses([]);
        setActiveProcessId(null);
        setLoadedProcessId(null); // Clear loaded tracker
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        setPrivacySettings(DEFAULT_PRIVACY);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
        if (data.privacySettings) setPrivacySettings(data.privacySettings);

        if (data.processes && data.processes.length > 0) {
            setProcesses(data.processes);
            if(data.activeProcessId) setActiveProcessId(data.activeProcessId);
        } else if (data.scopes && data.scopes.length > 0) {
             const migrated = data.scopes.map((s: any) => ({
                 ...s,
                 interviewees: [] 
             }));
             setProcesses(migrated);
             if(data.activeScopeId) setActiveProcessId(data.activeScopeId);
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    const contextValue = useMemo(() => ({
        standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
        auditInfo, setAuditInfo,
        privacySettings, setPrivacySettings,
        processes, activeProcessId, activeProcess, setActiveProcessId, addProcess, renameProcess, deleteProcess, batchUpdateProcessClauses, toggleProcessClause,
        addInterviewee, removeInterviewee,
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, setSelectedClauses,
        knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
        analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
        resetSession, restoreSession
    }), [
        standards, standardKey, customStandards, auditInfo, privacySettings,
        processes, activeProcessId, activeProcess,
        evidence, matrixData, evidenceTags,
        selectedClauses, knowledgeBase, knowledgeFileName,
        analysisResult, selectedFindings, finalReportText
    ]);

    return (
        <AuditContext.Provider value={contextValue}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

